// Processar dados dos alunos e preparar para WhatsApp
const students = $input.all();
const processed = [];

for (const student of students) {
  const data = student.json;

  // Verificar se tem celular válido
  const celular = data.celular || data.telefone || data.Celular || data.Telefone;
  if (!celular) continue;

  // Formatar número WhatsApp (Matupá-MT código 65)
  let whatsapp = celular.toString().replace(/\D/g, '');

  // Adicionar código de área 5565 se necessário
  if (whatsapp.length === 9) {
    whatsapp = '5565' + whatsapp;
  } else if (whatsapp.length === 11 && whatsapp.startsWith('65')) {
    whatsapp = '55' + whatsapp;
  } else if (whatsapp.length === 10 && whatsapp.startsWith('65')) {
    whatsapp = '55' + whatsapp;
  }

  // Classificar por segmento baseado na idade (simulação)
  let segmento = 'FRIO';
  let template = 'FRIO';

  if (data.idade || data.Idade) {
    const idade = parseInt(data.idade || data.Idade);
    if (idade < 25) {
      segmento = 'QUENTE';
      template = 'QUENTE';
    } else if (idade < 35) {
      segmento = 'MORNO';
      template = 'MORNO';
    }
  }

  // Extrair primeiro nome
  const nomeCompleto = data.nome_completo || data.nome || data.Nome || data['Nome Completo'] || '';
  const primeiroNome = nomeCompleto.split(' ')[0];

  processed.push({
    nome_completo: nomeCompleto,
    primeiro_nome: primeiroNome,
    celular: celular,
    whatsapp: whatsapp,
    idade: data.idade || data.Idade,
    segmento: segmento,
    template: template,
    email: data.email || data.Email
  });
}

// Limitar a 20 para teste inicial (respeitar rate limit)
const limited = processed.slice(0, 20);

return limited.map(item => ({ json: item }));

// Templates de mensagem por segmento
const templates = {
  QUENTE: "Oi {{$json.primeiro_nome}}! 🏋️ Sentimos sua falta na Full Force! Que tal voltarmos aos treinos? Posso agendar um horário especial pra você essa semana? 💪",
  MORNO: "{{$json.primeiro_nome}}, preparamos um PLANO DE RETORNO especial pra você! ✅ Avaliação gratuita ✅ Programa personalizado ✅ Acompanhamento exclusivo. Responda EU QUERO! 🔥",
  FRIO: "{{$json.primeiro_nome}}, que tal uma SEGUNDA CHANCE? 🎯 Oferta especial: 🎁 7 dias grátis 🎁 Reavaliação completa 🎁 Novo plano de treino. Válido até o fim do mês!"
};

const data = $json;
const template = templates[data.template] || templates.FRIO;
const message = template.replace(/{{\$json\.primeiro_nome}}/g, data.primeiro_nome);

return {
  ...data,
  message: message
};
